/**
 * @name Path traversal in log file reading via HTTP request
 * @description User-controlled log path from HTTP request reaches file operations without proper validation
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-log-http
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module LogPathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module LogPathTraversalFlow = TaintTracking::Global<LogPathTraversalConfig>;
import LogPathTraversalFlow::PathGraph

from LogPathTraversalFlow::PathNode source, LogPathTraversalFlow::PathNode sink
where LogPathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: user-controlled value flows to file operation from $@.", source.getNode(), "user input"

/**
